# Custom Iterator Implementation
class SquareSequence:
    def __init__(self, limit):
        self.limit = limit
        self.curr = 1
    def __iter__(self):
        return self
    def __next__(self):
        if self.curr > self.limit:
            raise StopIteration
        res = self.curr ** 2
        self.curr += 1
        return res

for val in SquareSequence(3):
    print(val)  # 1, 4, 9
